# lib/blog/posts/post.ex
defmodule Blog.Posts.Post do
  use Ecto.Schema
  import Ecto.Changeset

  schema "posts" do
    field :title, :string
    field :content, :string
    field :sanitized_content, :string
    belongs_to :user, Blog.Accounts.User

    timestamps()
  end

  @doc """
  Sanitizes HTML content on save, allowing safe formatting tags
  but stripping scripts, event handlers, and other dangerous content.
  """
  def changeset(post, attrs) do
    post
    |> cast(attrs, [:title, :content, :user_id])
    |> validate_required([:title, :content, :user_id])
    |> sanitize_content()
  end

  defp sanitize_content(changeset) do
    case get_change(changeset, :content) do
      nil -> changeset
      content ->
        sanitized = HtmlSanitizeEx.basic_html(content)
        put_change(changeset, :sanitized_content, sanitized)
    end
  end
end

# lib/blog_web/helpers/sanitize_helper.ex
defmodule BlogWeb.SanitizeHelper do
  @moduledoc """
  Helper for safely rendering user-generated HTML content.
  Never use raw() directly with unsanitized user input.
  """

  @doc """
  Renders user HTML content safely by sanitizing it first.
  Allows basic formatting: <b>, <i>, <p>, <br>, <ul>, <ol>, <li>,
  <h1>-<h6>, <blockquote>, <a href>, <img src>, <em>, <strong>, <code>, <pre>
  """
  def safe_html(nil), do: ""

  def safe_html(content) when is_binary(content) do
    content
    |> HtmlSanitizeEx.basic_html()
    |> Phoenix.HTML.raw()
  end
end

# lib/blog_web/live/post_live/show.ex
defmodule BlogWeb.PostLive.Show do
  use BlogWeb, :live_view

  import BlogWeb.SanitizeHelper

  alias Blog.Posts

  @impl true
  def mount(%{"id" => id}, _session, socket) do
    post = Posts.get_post!(id)
    {:ok, assign(socket, :post, post)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto py-8">
      <article class="prose lg:prose-xl">
        <h1><%= @post.title %></h1>

        <div class="post-meta text-gray-500 text-sm mb-6">
          <span>By <%= @post.user.name %></span>
          <span> · </span>
          <span><%= Calendar.strftime(@post.inserted_at, "%B %d, %Y") %></span>
        </div>

        <%!--
          SECURE: We use safe_html/1 which sanitizes content before rendering.

          NEVER DO THIS with user content:
            <%= raw @post.content %>

          ALWAYS DO THIS:
            <%= safe_html(@post.content) %>

          Or use the pre-sanitized field:
            <%= raw @post.sanitized_content %>
        --%>
        <div class="post-content">
          <%= safe_html(@post.content) %>
        </div>
      </article>
    </div>
    """
  end
end

# lib/blog_web/live/post_live/index.ex
defmodule BlogWeb.PostLive.Index do
  use BlogWeb, :live_view

  import BlogWeb.SanitizeHelper

  alias Blog.Posts

  @impl true
  def mount(_params, _session, socket) do
    posts = Posts.list_posts()
    {:ok, assign(socket, :posts, posts)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto py-8">
      <h1 class="text-3xl font-bold mb-8">Blog Posts</h1>

      <div class="space-y-8">
        <article :for={post <- @posts} class="border-b pb-6">
          <h2 class="text-2xl font-semibold">
            <.link navigate={~p"/posts/#{post.id}"}>
              <%= post.title %>
            </.link>
          </h2>

          <div class="post-excerpt prose mt-2">
            <%= safe_html(truncate_html(post.content, 300)) %>
          </div>
        </article>
      </div>
    </div>
    """
  end

  defp truncate_html(nil, _), do: ""
  defp truncate_html(content, max_length) do
    content
    |> HtmlSanitizeEx.strip_tags()
    |> String.slice(0, max_length)
    |> Kernel.<>("...")
  end
end

# lib/blog_web/live/post_live/form.ex
defmodule BlogWeb.PostLive.Form do
  use BlogWeb, :live_view

  import BlogWeb.SanitizeHelper

  alias Blog.Posts
  alias Blog.Posts.Post

  @impl true
  def mount(_params, _session, socket) do
    changeset = Posts.change_post(%Post{})

    {:ok,
     socket
     |> assign(:changeset, changeset)
     |> assign(:preview, nil)}
  end

  @impl true
  def handle_event("validate", %{"post" => post_params}, socket) do
    changeset =
      %Post{}
      |> Posts.change_post(post_params)
      |> Map.put(:action, :validate)

    {:noreply, assign(socket, :changeset, changeset)}
  end

  @impl true
  def handle_event("preview", %{"post" => post_params}, socket) do
    {:noreply, assign(socket, :preview, post_params["content"])}
  end

  @impl true
  def handle_event("save", %{"post" => post_params}, socket) do
    case Posts.create_post(post_params) do
      {:ok, post} ->
        {:noreply,
         socket
         |> put_flash(:info, "Post created successfully")
         |> push_navigate(to: ~p"/posts/#{post.id}")}

      {:error, changeset} ->
        {:noreply, assign(socket, :changeset, changeset)}
    end
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto py-8">
      <h1 class="text-3xl font-bold mb-8">New Post</h1>

      <.form for={@changeset} phx-change="validate" phx-submit="save" class="space-y-6">
        <div>
          <label class="block text-sm font-medium">Title</label>
          <input type="text" name="post[title]" value={@changeset.changes[:title]}
                 class="mt-1 block w-full rounded-md border-gray-300" />
        </div>

        <div>
          <label class="block text-sm font-medium">
            Content (HTML formatting allowed: bold, italic, links, lists, headings, images)
          </label>
          <textarea name="post[content]" rows="15"
                    class="mt-1 block w-full rounded-md border-gray-300 font-mono text-sm">
            <%= @changeset.changes[:content] %>
          </textarea>
          <p class="mt-1 text-xs text-gray-500">
            Allowed tags: &lt;b&gt;, &lt;i&gt;, &lt;em&gt;, &lt;strong&gt;, &lt;p&gt;,
            &lt;br&gt;, &lt;ul&gt;, &lt;ol&gt;, &lt;li&gt;, &lt;h1&gt;-&lt;h6&gt;,
            &lt;blockquote&gt;, &lt;a&gt;, &lt;img&gt;, &lt;code&gt;, &lt;pre&gt;.
            Scripts and event handlers are automatically removed for security.
          </p>
        </div>

        <div class="flex gap-4">
          <button type="submit" class="bg-blue-600 text-white px-4 py-2 rounded-md">
            Publish Post
          </button>
          <button type="button" phx-click="preview" phx-value-content={@changeset.changes[:content]}
                  class="bg-gray-200 px-4 py-2 rounded-md">
            Preview
          </button>
        </div>
      </.form>

      <%= if @preview do %>
        <div class="mt-8 border-t pt-8">
          <h2 class="text-xl font-semibold mb-4">Preview (sanitized)</h2>
          <div class="prose lg:prose-xl bg-gray-50 p-6 rounded-lg">
            <%= safe_html(@preview) %>
          </div>
        </div>
      <% end %>
    </div>
    """
  end
end

# Optional: Custom sanitizer for more control over allowed tags
# lib/blog/html_sanitizer.ex
defmodule Blog.HtmlSanitizer do
  @moduledoc """
  Custom HTML sanitizer with a curated allowlist of tags and attributes
  suitable for blog post content.
  """

  @allowed_tags ~w(
    p br div span
    h1 h2 h3 h4 h5 h6
    b i em strong u s strike del
    ul ol li
    blockquote pre code
    a img
    table thead tbody tr th td
    hr sup sub
    figure figcaption
  )

  @allowed_attributes %{
    "a" => ["href", "title", "rel"],
    "img" => ["src", "alt", "title", "width", "height"],
    "td" => ["colspan", "rowspan"],
    "th" => ["colspan", "rowspan"],
    "code" => ["class"],
    "pre" => ["class"],
    "div" => ["class"],
    "span" => ["class"]
  }

  @doc """
  Sanitizes HTML allowing only safe tags and attributes for blog content.
  Strips all JavaScript, event handlers, and dangerous protocols.
  """
  def sanitize(nil), do: ""

  def sanitize(html) when is_binary(html) do
    html
    |> HtmlSanitizeEx.Scrubber.scrub(Blog.HtmlSanitizer.Scrubber)
  end

  def safe_html(content) do
    content
    |> sanitize()
    |> Phoenix.HTML.raw()
  end
end

# lib/blog/html_sanitizer/scrubber.ex
defmodule Blog.HtmlSanitizer.Scrubber do
  @moduledoc """
  Custom scrubber rules for HtmlSanitizeEx.
  """

  require HtmlSanitizeEx.Scrubber.Meta
  alias HtmlSanitizeEx.Scrubber.Meta

  # Strip comments
  Meta.strip_comments()

  # Allow safe URI schemes only
  Meta.allow_tag_with_uri_attributes("a", ["href"], ["http", "https", "mailto"])
  Meta.allow_tag_with_uri_attributes("img", ["src"], ["http", "https"])

  # Allow specific attributes on tags
  Meta.allow_tag_with_these_attributes("a", ["title", "rel"])
  Meta.allow_tag_with_these_attributes("img", ["alt", "title", "width", "height"])
  Meta.allow_tag_with_these_attributes("code", ["class"])
  Meta.allow_tag_with_these_attributes("pre", ["class"])

  # Allow formatting tags without attributes
  Enum.each(~w(p br div span h1 h2 h3 h4 h5 h6 b i em strong u s del
               ul ol li blockquote hr sup sub table thead tbody tr td th
               figure figcaption), fn tag ->
    Meta.allow_tag_with_these_attributes(tag, [])
  end)

  # Strip everything else
  Meta.strip_everything_not_covered()
end